import{_ as a,o as i,c as t,a4 as s}from"./chunks/framework.COJ7LtHI.js";const g=JSON.parse('{"title":"Codex plugin","description":"Install and use the JSVision Codex plugin in any TypeScript project.","frontmatter":{"title":"Codex plugin","description":"Install and use the JSVision Codex plugin in any TypeScript project."},"headers":[],"relativePath":"guide/codex-plugin.md","filePath":"guide/codex-plugin.md"}'),n={name:"guide/codex-plugin.md"};function o(l,e,r,d,p,c){return i(),t("div",null,[...e[0]||(e[0]=[s(`<h1 id="codex-plugin" tabindex="-1">Codex plugin <a class="header-anchor" href="#codex-plugin" aria-label="Permalink to &quot;Codex plugin&quot;">​</a></h1><p>The JSVision Codex plugin gives Codex version-matched framework guidance, generated public API references, standalone project scaffolding, static diagnostics, and headless screen rendering. It works in consumer projects that install JSVision from npm; a JSVision monorepo checkout is not required.</p><h2 id="install-from-the-marketplace" tabindex="-1">Install from the marketplace <a class="header-anchor" href="#install-from-the-marketplace" aria-label="Permalink to &quot;Install from the marketplace&quot;">​</a></h2><p>Add the marketplace at the tag matching the latest stable JSVision release, then install the plugin:</p><div class="language-sh vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">codex</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> plugin</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> marketplace</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> add</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> blendsdk/jsvision</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --ref</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> v1.0.0</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">codex</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> plugin</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> add</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> jsvision-plugin@jsvision-marketplace</span></span></code></pre></div><p>Start a new Codex thread after installation so its skills are discovered. The plugin version stays in lockstep with the stable <code>@jsvision/*</code> package version.</p><h2 id="use-the-plugin" tabindex="-1">Use the plugin <a class="header-anchor" href="#use-the-plugin" aria-label="Permalink to &quot;Use the plugin&quot;">​</a></h2><p>Ask Codex to build, extend, debug, test, or review a JSVision application. The main <code>jsvision</code> skill can trigger automatically, or you can invoke it explicitly:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Use $jsvision to build a keyboard-first inventory application.</span></span></code></pre></div><p>The plugin includes four skills:</p><table tabindex="0"><thead><tr><th>Skill</th><th>Purpose</th></tr></thead><tbody><tr><td><code>$jsvision</code></td><td>Architecture, public APIs, components, layout, reactivity, forms, grids, files, themes, and production quality</td></tr><tr><td><code>$jsvision-new-app</code></td><td>Create a standalone Node 22+, ESM TypeScript project using published JSVision packages</td></tr><tr><td><code>$jsvision-doctor</code></td><td>Detect common layout, lifecycle, focus, modal, and NodeNext mistakes</td></tr><tr><td><code>$jsvision-render</code></td><td>Render an application or view as a deterministic headless text screenshot</td></tr></tbody></table><h2 id="create-a-standalone-application" tabindex="-1">Create a standalone application <a class="header-anchor" href="#create-a-standalone-application" aria-label="Permalink to &quot;Create a standalone application&quot;">​</a></h2><p>Ask Codex to create an app and describe the desired starting point. The generator supports basic, form, grid, and dashboard starters. It:</p><ol><li>Detects npm, Yarn, pnpm, or Bun from project metadata and lockfiles.</li><li>Asks when package-manager detection is ambiguous and otherwise falls back to npm.</li><li>Creates a new subdirectory by default.</li><li>Requires explicit confirmation before writing into the current directory.</li><li>Installs dependencies automatically with the selected package manager.</li><li>Refuses path traversal and conflicting files.</li></ol><p>Generated applications export <code>buildApp()</code> for tests and headless rendering while keeping terminal startup behind a direct-execution guard.</p><h2 id="diagnose-and-render" tabindex="-1">Diagnose and render <a class="header-anchor" href="#diagnose-and-render" aria-label="Permalink to &quot;Diagnose and render&quot;">​</a></h2><p>The doctor uses the consumer project&#39;s TypeScript compiler. When TypeScript is absent, Codex asks before adding it as a development dependency.</p><p>The renderer accepts modules exporting <code>buildApp</code>, <code>build</code>, or a default factory. If an application uses another entry shape, add a small adapter export rather than executing its uncontrolled startup path. Render at normal and constrained terminal sizes and use driven key sequences to inspect interaction states.</p><h2 id="version-sensitive-guidance" tabindex="-1">Version-sensitive guidance <a class="header-anchor" href="#version-sensitive-guidance" aria-label="Permalink to &quot;Version-sensitive guidance&quot;">​</a></h2><p>The plugin targets the latest stable JSVision release. It inspects the consumer project&#39;s installed package versions and public declarations before relying on version-sensitive details. Upgrade the packages and plugin together when they differ.</p><h2 id="update" tabindex="-1">Update <a class="header-anchor" href="#update" aria-label="Permalink to &quot;Update&quot;">​</a></h2><p>Refresh the tagged marketplace snapshot, reinstall the plugin, and start a new thread:</p><div class="language-sh vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">codex</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> plugin</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> marketplace</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> upgrade</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> jsvision-marketplace</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">codex</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> plugin</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> add</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> jsvision-plugin@jsvision-marketplace</span></span></code></pre></div><p>To move to a newer stable release, re-add the marketplace with that release tag before reinstalling.</p><h2 id="troubleshooting" tabindex="-1">Troubleshooting <a class="header-anchor" href="#troubleshooting" aria-label="Permalink to &quot;Troubleshooting&quot;">​</a></h2><ul><li><strong>Plugin not listed:</strong> run <code>codex plugin marketplace list</code> and confirm <code>jsvision-marketplace</code> is configured at the intended stable tag.</li><li><strong>Skill changes are not visible:</strong> reinstall the plugin and start a new Codex thread.</li><li><strong>Doctor cannot find TypeScript:</strong> install TypeScript in the consumer project after approving the package-manager command.</li><li><strong>Renderer cannot resolve JSVision:</strong> install the stable <code>@jsvision/ui</code> package in the project containing the module being rendered.</li><li><strong>Renderer cannot find an entry:</strong> export <code>buildApp</code>, <code>build</code>, or a default factory that constructs the app without connecting to the terminal.</li></ul>`,26)])])}const u=a(n,[["render",o]]);export{g as __pageData,u as default};
